import React, { useState, useEffect } from 'react';
import { courtierAPI } from '../../services/courtierAPI';
import CourtierStats from './CourtierStats';
import CourtierDossiers from './CourtierDossiers';
import CourtierClients from './CourtierClients';
import './Courtier.css';

const NAV = [
  { id: 'stats',    label: 'Vue d\'ensemble',  icon: 'ti ti-layout-dashboard' },
  { id: 'dossiers', label: 'Dossiers',          icon: 'ti ti-folder' },
  { id: 'clients',  label: 'Clients',           icon: 'ti ti-users' },
];

export default function CourtierDashboard() {
  const [active, setActive] = useState('stats');
  const [collapsed, setCollapsed] = useState(false);
  const [stats, setStats] = useState(null);
  const [statsLoading, setStatsLoading] = useState(true);

  useEffect(() => {
    courtierAPI.getStats()
      .then((r) => setStats(r.data))
      .catch(() => {})
      .finally(() => setStatsLoading(false));
  }, []);

  const PAGE_TITLES = {
    stats: 'Vue d\'ensemble',
    dossiers: 'Mes dossiers',
    clients: 'Mes clients',
  };

  const handleLogout = () => {
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    window.location.href = '/login';
  };

  return (
    <div className="crt-layout">
      {/* SIDEBAR */}
      <aside className={`crt-sidebar${collapsed ? ' collapsed' : ''}`}>
        <div className="crt-sidebar-brand">
          <div className="brand-icon"><i className="ti ti-shield-check" /></div>
          <span className="brand-text">Courtier</span>
        </div>

        <nav className="crt-nav">
          {NAV.map((item) => (
            <button
              key={item.id}
              className={`crt-nav-btn${active === item.id ? ' crt-nav-btn--active' : ''}`}
              onClick={() => setActive(item.id)}
            >
              <i className={item.icon} aria-hidden="true" />
              <span>{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="crt-sidebar-footer">
          <button className="crt-nav-btn" onClick={handleLogout}>
            <i className="ti ti-logout" />
            <span>Déconnexion</span>
          </button>
          <button className="crt-collapse-btn" onClick={() => setCollapsed((c) => !c)}>
            <i className={`ti ${collapsed ? 'ti-layout-sidebar-right' : 'ti-layout-sidebar'}`} />
            <span>{collapsed ? '' : 'Réduire'}</span>
          </button>
        </div>
      </aside>

      {/* MAIN */}
      <div className="crt-main">
        <header className="crt-header">
          <h1>{PAGE_TITLES[active]}</h1>
          <div className="crt-header-actions">
            {active === 'stats' && !statsLoading && stats && (
              <span style={{ fontSize: 13, color: 'var(--crt-muted)' }}>
                Score moyen portefeuille:&nbsp;
                <span style={{ color: 'var(--crt-accent)', fontWeight: 600 }}>{stats.score_moyen}</span>
              </span>
            )}
          </div>
        </header>

        <div className="crt-content">
          {active === 'stats' && (
            statsLoading
              ? <div className="crt-loading"><i className="ti ti-loader" /> Chargement...</div>
              : <CourtierStats stats={stats} />
          )}
          {active === 'dossiers' && <CourtierDossiers />}
          {active === 'clients' && <CourtierClients />}
        </div>
      </div>
    </div>
  );
}
